create table if not exists profiles(id uuid primary key default gen_random_uuid(), anonymous_name text, language text default 'english', ai_persona text default 'supportive_friend', onboarding_completed boolean default false, created_at timestamptz default now());
create table if not exists mood_checkins(id uuid primary key default gen_random_uuid(), user_id text, mood_score int check(mood_score between 1 and 10), note text, created_at timestamptz default now());
create table if not exists journal_entries(id uuid primary key default gen_random_uuid(), user_id text, content text not null, mood_score int, is_private boolean default true, created_at timestamptz default now());
create table if not exists rooms(id uuid primary key default gen_random_uuid(), name text not null, theme text, description text, max_participants int default 8, is_active boolean default true, created_at timestamptz default now());
create table if not exists messages(id uuid primary key default gen_random_uuid(), room_id text, sender_id text, sender_name text, content text not null, is_flagged boolean default false, moderation_status text default 'safe', created_at timestamptz default now());
create table if not exists reports(id uuid primary key default gen_random_uuid(), reporter_id text, reported_user_id text, message_id text, reason text, description text, status text default 'pending', created_at timestamptz default now());
create table if not exists crisis_resources(id uuid primary key default gen_random_uuid(), name text not null, phone text, website text, description text, resource_type text default 'helpline', is_emergency boolean default false);
